from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismOpenSceneNode(BaseNode):
    name = "Prism: Open Scene"
    category = "DCCs"

    def __init__(self):
        super().__init__()
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("scene_path", "string", widget_type="file")
        self.add_output("success", "bool")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        path = inputs.get('scene_path') or ''
        if core is None:
            self.log_error("No PrismCore found. Add a prism_core_init node to your graph and connect its exec_out before this node.")
            return {'success': False}
        try:
            opened = False
            if hasattr(core, 'openScene'):
                core.openScene(path)
                opened = True
            elif getattr(core, 'appPlugin', None) is not None and hasattr(core.appPlugin, 'openScene'):
                core.appPlugin.openScene(core, path)
                opened = True
            else:
                self.log_error("No openScene method available on this PrismCore.")
            if opened:
                self.log_success(f"Opened scene: {path}")
                await self.set_output('exec_out', True)
            return {'success': opened}
        except Exception as e:
            self.log_error(f"openScene failed: {e}")
            return {'success': False}

def register_node():
    return PrismOpenSceneNode
